export const APP_CSS = `
body{margin:0;background:#141414;color:#fff;font-family:Inter,system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif}
a{color:inherit;text-decoration:none}button,input,select{font:inherit}.container-netflix{width:min(1180px,calc(100% - 32px));margin-inline:auto}
.header-container{background:linear-gradient(to bottom,rgba(0,0,0,.82),rgba(0,0,0,0));position:fixed;top:0;z-index:50;width:100%}
.btn-primary{background:#dc2626;color:#fff}.btn-primary:hover{background:#b91c1c}.btn-secondary{background:rgba(75,85,99,.85);color:#fff}
.hero-section{height:70vh;min-height:480px;position:relative}.hero-image{width:100%;height:100%;object-fit:cover;opacity:.42}.hero-gradient-bg{height:100%;background:linear-gradient(135deg,rgba(153,27,27,.25),#000)}
.hero-overlay-left{background:linear-gradient(to right,#141414,rgba(20,20,20,.62),transparent)}.hero-overlay-bottom{background:linear-gradient(to top,#141414,transparent)}
.stats-bar{background:rgba(0,0,0,.5)}.movies-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(140px,1fr));gap:14px}
.movie-card{transition:transform .2s ease}.movie-card:hover{transform:scale(1.03)}.poster-container{aspect-ratio:2/3;border-radius:8px;background:#18181b;overflow:hidden}.poster-image{width:100%;height:100%;object-fit:cover}
.card-overlay{opacity:0}.movie-card:hover .card-overlay{opacity:1}.alert-success{padding:1rem;border:1px solid rgba(16,185,129,.45);background:rgba(16,185,129,.18);color:#a7f3d0;border-radius:8px}
.input-field{box-sizing:border-box}.empty-state{min-height:360px}.hidden{display:none!important}
`;

export const APP_JS = `
window.confirmDelete=(title)=>confirm('Tem certeza que deseja remover "'+title+'" da sua lista?');
document.addEventListener("DOMContentLoaded",()=>{const title=document.getElementById("title");const suggestions=document.getElementById("suggestions");if(!title||!suggestions)return;const radios=document.querySelectorAll('input[name="type"]');const language=document.getElementById("language");const series=document.getElementById("seriesFields");const titleType=document.getElementById("titleType");const submit=document.getElementById("submitText");let type="movie";let timer=null;radios.forEach(r=>r.addEventListener("change",()=>{type=r.value;if(series)series.classList.toggle("hidden",type!=="series");if(titleType)titleType.textContent=type==="series"?"da Série":"do Filme";if(submit)submit.textContent=type==="series"?"Adicionar Série":"Adicionar Filme";suggestions.innerHTML="";suggestions.classList.add("hidden")}));title.addEventListener("input",()=>{clearTimeout(timer);const q=title.value.trim();if(q.length<2){suggestions.classList.add("hidden");return}timer=setTimeout(async()=>{const res=await fetch("/movies/search?q="+encodeURIComponent(q)+"&type="+type+"&language="+(language?.value||"pt-BR"));if(!res.ok){suggestions.classList.add("hidden");return}const items=await res.json();suggestions.innerHTML=items.map(item=>'<button type="button" data-title="'+esc(item.title||'')+'" data-tmdb-id="'+esc(String(item.tmdb_id||''))+'" data-imdb-id="'+esc(String(item.imdb_id||''))+'" class="suggestion-item flex w-full items-center gap-4 border-b border-gray-800 px-4 py-3 text-left transition hover:bg-zinc-900 last:border-b-0">'+(item.poster?'<img src="'+esc(item.poster)+'" class="h-16 w-11 rounded object-cover shadow-lg" loading="lazy">':'')+'<span>'+esc(item.title||'')+(item.year?' ('+esc(item.year)+')':'')+'</span></button>').join("");suggestions.classList.toggle("hidden",items.length===0);suggestions.querySelectorAll("button").forEach(button=>button.addEventListener("click",()=>{title.value=button.dataset.title||"";setHidden("tmdb_id",button.dataset.tmdbId||"");setHidden("imdb_id",button.dataset.imdbId||"");suggestions.classList.add("hidden")}))},350)});function setHidden(name,value){let input=document.getElementById(name);if(!input){input=document.createElement("input");input.type="hidden";input.id=name;input.name=name;document.getElementById("movieForm").appendChild(input)}input.value=value}function esc(value){return String(value).replace(/[&<>"']/g,(char)=>({"&":"&amp;","<":"&lt;",">":"&gt;","\\"":"&quot;","'":"&#039;"}[char]))}});
`;
